#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 255;
int n, b;
int dp[N][N];
int f[N];
int s[N];
int d[N];
signed main() {
	cin >> n >> b;
	for (int i = 1; i <= n; i++) {
		cin >> f[i];
	}
	for (int i = 1; i <= b; i++) {
		cin >> s[i] >> d[i];
	}
	dp[1][1] = 1;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= b; j++) {
			if (dp[i][j]) {
				for (int k = j; k <= b; k++) {
					if (f[i] <= s[k]) {
						for (int l = i + 1; l <= min (n, i + d[k]); l++) {
							if (f[l] <= s[k]) {
								dp[l][k] = 1;
							}
						}
					}
				}
			}
		}
	}
    for (int i = 1; i <= b; i++) {
    	if (dp[n][i]) {
    		cout << i - 1;
    		return 0;
		}
	}
	return 0;
}
